import { readFile, writeFile } from "node:fs/promises"
import { fileURLToPath } from "node:url"

const templateDirectory = new URL(
  "../node_modules/uniffi-bindgen-react-native/crates/ubrn_cli/templates/wasm/",
  import.meta.url,
)

await patchTemplate("Cargo.toml.txt", new Map([
  ['wasm-bindgen = "*"', 'wasm-bindgen = "=0.2.126"\nconsole_error_panic_hook = "0.1.7"'],
  ['opt-level = "3"', "opt-level = 3"],
]))

await patchTemplate("lib.rs", new Map([
  [
    "// Generated by uniffi-bindgen-react-native\n\n{{ entrypoint() }}",
    `// Generated by uniffi-bindgen-react-native

use wasm_bindgen::prelude::wasm_bindgen;

#[wasm_bindgen(start)]
pub fn initialize_panic_hook() {
    console_error_panic_hook::set_once();
}

{{ entrypoint() }}`,
  ],
]))

async function patchTemplate(name, replacements) {
  const templatePath = fileURLToPath(new URL(name, templateDirectory))
  let source = await readFile(templatePath, "utf8")

  for (const [invalid, valid] of replacements) {
    const matches = source.split(invalid).length - 1
    if (matches !== 1) {
      throw new Error(`expected exactly one ${invalid} in ${templatePath}, found ${matches}`)
    }
    source = source.replace(invalid, valid)
  }

  await writeFile(templatePath, source)
}
